import React from 'react';
import { Grommet, Header, Text }  from 'grommet';

const theme = {

    global: {

        font: {
            family: "Roboto",
            size: "24px",
            height: "20px"
        },

        colors: {

            brand: '#228BE6'

        },

    },

}

const AppBar = (props) => (

    <Header
        background="brand"
        pad = {{left: "medium", right: "small", vertical: "small"}}
        elevation = "medium"  
    />

);

const App = () => {
  return (
    <Grommet theme = {theme} full>
        <AppBar>

            <Text size="large">My App</Text>

        </AppBar>
    </Grommet>
  );
};

export default App;
